For example

BaseCondtion can be copied, pasted,duplicated, but conditions can't, and copying ConditionTable would only have a list with "none" elements.

```
[System.Serializable]
public class ConditionTable
{

	[Label("ConditonList",skinStyle: SkinStyle.Box)] 
	[ReorderableList(Foldable = true)]
	[SerializeReference,ReferencePicker(ParentType = typeof(BaseCondition))]
	public List<BaseCondition> conditions = new List<BaseCondition>();

	public virtual bool IsTrue(Transform _inputTransform = null)
	{
		foreach (var condition in conditions)
		{
			if(condition == null)
				continue;

			if(!condition.IsTrue(_inputTransform))
				return false;
		}

		return true;
	}
}

[System.Serializable]
public class BaseCondition
{
	[Label("State",skinStyle: SkinStyle.Box)]
	[SerializeField]
	private bool m_useCondition = true;
	public bool useCondition
	{
		get => m_useCondition;
		set => m_useCondition = value;
	}

	public virtual bool IsTrue(Transform _inputTransform = null)
	{
		if(!useCondition)
			return true;

		return false;
	}
}
```

